import{_ as s,o as i,c as t,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Sponsored social","description":"","frontmatter":{"title":"Sponsored social"},"headers":[],"relativePath":"docs/fr/advertisers/sponsored-social/index.md","filePath":"docs/fr/advertisers/sponsored-social/index.md"}'),r={name:"docs/fr/advertisers/sponsored-social/index.md"};function o(d,e,n,l,p,c){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="sponsored-social-retail-media" tabindex="-1">Sponsored Social (Retail Media) <a class="header-anchor" href="#sponsored-social-retail-media" aria-label="Permalink to &quot;Sponsored Social (Retail Media)&quot;">​</a></h1><p>Diffusez vos contenus publicitaires via les comptes sociaux de nos e-commerçants partenaires (Instagram, Facebook, TikTok).</p><div class="mt-4 mb-6"><a href="workflow" class="btn btn-primary fs-4 mr-2">Voir le Process</a><a href="specs" class="btn btn-outline fs-4">Specs Techniques</a></div><hr class="mb-6"><h2 class="text-blue-200 mb-4">Pourquoi ce levier est puissant ?</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(280px, 1fr));gap:20px;margin-bottom:40px;width:100%;"><div style="border:1px solid #e1e4e8;border-radius:8px;padding:24px;background:#f6f8fa;"><h3 class="mt-0 text-blue-200">🤝 Endorsement (Caution)</h3><p>Vous ne parlez pas en votre nom, mais via la voix d&#39;un e-commerçant aimé par sa communauté.</p><ul class="mb-0 fs-2"><li>Crédibilité accrue.</li><li>Contournement de la &quot;Banner Blindness&quot;.</li><li>Taux de conversion supérieur.</li></ul></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:24px;background:#fff;"><h3 class="mt-0 text-blue-200">🎯 Audience Affinitaire</h3><p>Touchez les followers de marques de niche (Beauté, Tech, Food...) directement dans leur feed.</p><div style="margin-top:15px;font-size:0.9em;color:#586069;"><em>Exemple : Une marque de croquettes ciblant les abonnés d&#39;une animalerie en ligne.</em></div></div><div style="border:2px solid #2d6fd6;border-radius:8px;padding:24px;background:#fff;"><h3 class="mt-0 text-blue-200">🚀 Amplification Média</h3><p>Nous utilisons le format <strong>Partnership Ads</strong>.</p><p>Vous sponsorisez le post du distributeur pour toucher une audience large, bien au-delà de ses simples abonnés organiques.</p></div></div><h2 class="text-grey-dk-000 mb-4">Formats Disponibles</h2><div style="display:flex;gap:20px;flex-wrap:wrap;margin-bottom:40px;"><div style="flex:1;min-width:200px;border:1px solid #e1e4e8;border-radius:6px;padding:15px;text-align:center;background:#fff;"><div style="font-size:30px;margin-bottom:10px;">📸</div><strong>Social Post</strong><br><span class="fs-2 text-grey-dk-000">Photo ou Carrousel</span></div><div style="flex:1;min-width:200px;border:1px solid #2da44e;border-radius:6px;padding:15px;text-align:center;background:#f0fcf4;"><div style="font-size:30px;margin-bottom:10px;">🎥</div><strong>Social Video</strong><br><span class="fs-2 text-grey-dk-000">Reels &amp; TikTok (Vertical)</span><br><em style="font-size:12px;color:#2da44e;">Recommandé</em></div><div style="flex:1;min-width:200px;border:1px solid #e1e4e8;border-radius:6px;padding:15px;text-align:center;background:#fff;"><div style="font-size:30px;margin-bottom:10px;">⏱️</div><strong>Story</strong><br><span class="fs-2 text-grey-dk-000">Format éphémère (24h)</span></div></div><h2 class="text-blue-200 mb-4">Pourquoi passer par getinside ?</h2><div style="display:flex;flex-direction:column;gap:20px;"><div style="border:1px solid #e1e4e8;border-radius:8px;padding:24px;background:#fff;display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">⚡</div><div><h3 class="mt-0">Activation à l&#39;échelle</h3><p class="fs-2 text-grey-dk-000 mb-0">Ne perdez plus de temps à contacter les marques une par une. Lancez des campagnes simultanées sur plusieurs comptes retailers depuis une interface unique.</p></div></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:24px;background:#fff;display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">🎯</div><div><h3 class="mt-0">Donnée Retail (First Party)</h3><p class="fs-2 text-grey-dk-000 mb-0">Le ciblage ne se base pas uniquement sur les &quot;intérêts&quot; sociaux, mais sur la <strong>clientèle réelle</strong> des e-commerçants. Touchez des acheteurs avérés.</p></div></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:24px;background:#fff;display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">⚙️</div><div><h3 class="mt-0">Setup Technique Simplifié</h3><p class="fs-2 text-grey-dk-000 mb-0">La configuration des &quot;Partnership Ads&quot; (Meta) ou &quot;Spark Ads&quot; (TikTok) est complexe. Nous guidons les éditeurs et vérifions les autorisations pour vous.</p></div></div></div>',10)])])}const x=s(r,[["render",o]]);export{m as __pageData,x as default};
